import CoreData
import Foundation

/// PersistenceController configures the Core Data stack.
/// - Model name: "SouvenirModel" (SouvenirModel.xcdatamodeld)
/// - Entities: Contact, Photo, Souvenir, Share
/// - CloudKit support can be enabled later by switching to NSPersistentCloudKitContainer
public final class PersistenceController {
    public static let shared = PersistenceController()

    // Track loaded model to prevent duplicates
    private static var loadedModel: NSManagedObjectModel?
    private static var modelConfigured = false
    private static let modelLock = NSLock()

    /// Force reset the model cache (use only for debugging)
    public static func resetModelCache() {
        modelLock.lock()
        defer { modelLock.unlock() }
        loadedModel = nil
        modelConfigured = false
        print("🔄 Model cache reset")
    }

    public let container: NSPersistentCloudKitContainer

    /// In-memory variant for previews/tests.
    /// Uses synchronous store loading to ensure entity descriptions are available.
    #if DEBUG
    public static let preview: PersistenceController = {
        print("🔍 Creating PersistenceController.preview")
        let controller = PersistenceController(inMemory: true, waitForStores: true)
        let context = controller.container.viewContext

        // Seed comprehensive preview data for Phase 12.1
        if controller.container.managedObjectModel.entitiesByName["ContactEntity"] != nil {
            let previewData = PreviewDataGenerator()
            previewData.generatePreviewData(in: context)
        } else {
            print("⚠️ Preview Core Data model missing ContactEntity. Skipping preview data seeding.")
        }

        try? context.save()
        print("✅ PersistenceController.preview ready")
        return controller
    }()
    #endif

    /// Initialize the persistence stack.
    /// - Parameters:
    ///   - inMemory: If true, stores data in memory (not persisted to disk). Useful for previews/tests.
    ///   - waitForStores: If true, blocks until stores are loaded (required for previews to avoid entity description issues).
    public init(inMemory: Bool = false, waitForStores: Bool = false) {
        print("🔍 PersistenceController.init(inMemory: \(inMemory), waitForStores: \(waitForStores))")
        let modelName = "SouvenirModel"

        // CRITICAL: Always go through sharedModel to guarantee exactly one
        // NSManagedObjectModel instance exists.  NSPersistentContainer(name:)
        // (without managedObjectModel:) would load a *second* copy from disk
        // and trigger "Multiple NSEntityDescriptions claim …" + the crash.
        let model = Self.sharedModel
        print("✅ Using NSManagedObjectModel instance (\(ObjectIdentifier(model)))")

        container = NSPersistentCloudKitContainer(name: modelName, managedObjectModel: model)

        guard let description = container.persistentStoreDescriptions.first else {
            fatalError("Missing persistent store description for SouvenirModel")
        }

        if inMemory {
            description.url = URL(fileURLWithPath: "/dev/null")
        }

        // For synchronous loading (previews/tests), disable async store loading
        // This ensures entity descriptions are available before we try to create objects
        description.shouldAddStoreAsynchronously = !waitForStores

        // Enable automatic migrations for future schema changes
        description.setOption(true as NSNumber, forKey: NSMigratePersistentStoresAutomaticallyOption)
        description.setOption(true as NSNumber, forKey: NSInferMappingModelAutomaticallyOption)

        // CloudKit sync only for on-disk stores — never for in-memory preview/test stores.
        // In-memory stores can't use CloudKit (no real store file for metadata),
        // and Swift Testing runs suites in parallel so multiple test instances would
        // race over CloudKit metadata tables and deadlock.
        if !inMemory {
            description.setOption(true as NSNumber, forKey: NSPersistentHistoryTrackingKey)
            description.setOption(true as NSNumber, forKey: NSPersistentStoreRemoteChangeNotificationPostOptionKey)
            description.cloudKitContainerOptions = NSPersistentCloudKitContainerOptions(
                containerIdentifier: "iCloud.ink.kerry.souvenir"
            )
        }

        // Use semaphore for truly synchronous loading when needed
        let semaphore = waitForStores ? DispatchSemaphore(value: 0) : nil

        container.loadPersistentStores { storeDescription, error in
            if let error = error as NSError? {
                // Log detailed error information
                print("❌ Failed to load persistent store at: \(storeDescription.url?.path ?? "unknown")")
                print("❌ Error: \(error)")
                print("❌ Error domain: \(error.domain)")
                print("❌ Error code: \(error.code)")
                print("❌ User info: \(error.userInfo)")

                // Common issues and solutions
                if error.domain == NSCocoaErrorDomain {
                    switch error.code {
                    case 134100: // Model mismatch
                        print("💡 Model version mismatch detected. The stored data doesn't match the current model.")
                        print("💡 Solutions:")
                        print("   1. Delete the app and reinstall (data will be lost)")
                        print("   2. Add a Core Data migration")
                        print("   3. If in development, delete: \(storeDescription.url?.path ?? "")")
                    case 134030: // Can't find model
                        print("💡 Core Data model file not found or entity configuration issue.")
                        print("💡 Check that SouvenirModel.xcdatamodeld is in your target.")
                    default:
                        print("💡 Unknown Core Data error. Check model configuration.")
                    }
                }

                fatalError("Unresolved error loading persistent stores: \(error), userInfo: \(error.userInfo)")
            }

            // Signal completion for synchronous loading
            semaphore?.signal()
        }

        // Wait for stores to load if synchronous loading was requested
        semaphore?.wait()

        // Context configuration
        let viewContext = container.viewContext
        viewContext.automaticallyMergesChangesFromParent = true
        viewContext.mergePolicy = NSMergeByPropertyObjectTrumpMergePolicy
        viewContext.name = "viewContext"
        viewContext.transactionAuthor = "app" // filter for later use of NSPersistentHistory
        // Performance optimizations
        viewContext.stalenessInterval = 0.0 // Always use fresh data
        viewContext.undoManager = nil // Disable undo for better performance

        // Listen for background context saves and merge
        NotificationCenter.default.addObserver(
            forName: .NSManagedObjectContextDidSave,
            object: nil,
            queue: .main
        ) { [weak viewContext] notification in
            guard let context = notification.object as? NSManagedObjectContext,
                  context !== viewContext,
                  context.persistentStoreCoordinator === viewContext?.persistentStoreCoordinator else {
                return
            }

            // Merge changes from background contexts
            viewContext?.mergeChanges(fromContextDidSave: notification)
            print("🔄 Merged changes from background context to viewContext")
        }

        print("✅ Core Data stack loaded successfully")
    }

    /// Returns the single shared model, loading it from disk only once.
    /// All code that needs an NSManagedObjectModel (containers, fetch requests,
    /// etc.) must go through this accessor instead of loading the .momd directly.
    ///
    /// Entity class resolution relies on each entity's `@objc(ClassName)` declaration
    /// combined with `representedClassName` in the model. Manual `managedObjectClassName`
    /// assignment is not used because versioned model bundles return a non-editable model
    /// from `NSManagedObjectModel(contentsOf:)`.
    public static var sharedModel: NSManagedObjectModel {
        modelLock.lock()
        defer { modelLock.unlock() }

        if let existing = loadedModel { return existing }

        let modelName = "SouvenirModel"
        let bundlesToSearch = [Bundle.main, Bundle(for: PersistenceController.self)]

        guard let modelURL = bundlesToSearch.lazy.compactMap({
            $0.url(forResource: modelName, withExtension: "momd")
        }).first,
              let model = NSManagedObjectModel(contentsOf: modelURL) else {
            fatalError("❌ Could not load \(modelName).momd")
        }

        print("🔍 Loaded NSManagedObjectModel (first time)")
        loadedModel = model
        modelConfigured = true
        return model
    }

    /// Create a new background context with sensible defaults.
    nonisolated public func newBackgroundContext() -> NSManagedObjectContext {
        let ctx = container.newBackgroundContext()
        ctx.mergePolicy = NSMergeByPropertyStoreTrumpMergePolicy
        ctx.automaticallyMergesChangesFromParent = true
        ctx.name = "backgroundContext"
        return ctx
    }

    /// Save the viewContext if there are pending changes.
    @discardableResult
    public func saveViewContext() throws -> Bool {
        let context = container.viewContext
        guard context.hasChanges else { return false }
        try context.save()
        return true
    }
}

