//
//  ViewsComponentsShareSheet.swift
//  souvenir
//
//  Phase 3: Sharing
//  Share sheet for souvenirs with SMS and in-app sharing options
//

import SwiftUI
import CoreData
import Photos
import MessageUI
import LinkPresentation
import UniformTypeIdentifiers
import UserNotifications

/// Share sheet presenting sharing options for a souvenir
struct ShareSheet: View {
    @ObservedObject var souvenir: SouvenirEntity
    @Environment(\.managedObjectContext) private var context
    @Environment(\.dismiss) private var dismiss

    @State private var shareEntity: ShareEntity?
    @State private var shareURL: URL?
    @State private var showingMessageCompose = false
    @State private var showingActivitySheet = false
    @State private var shareImage: UIImage?
    @State private var shareImageData: Data?
    @State private var isLoadingImage = false
    @State private var errorMessage: String?
    @State private var warnings: [String] = []
    @State private var showingNotificationsPrimer = false
    @AppStorage("svnrDidRequestPushPermission") private var didRequestPushPermission = false

    private let shareService = ShareService.shared
    private let photoLoader = PhotoLoadingService()

    var body: some View {
        NavigationStack {
            VStack(spacing: 24) {
                if !warnings.isEmpty {
                    WarningBanner(messages: warnings)
                }
                // Preview
                previewSection

                // Share options
                shareOptionsSection

                // Error display
                if let error = errorMessage {
                    Text(error)
                        .font(.caption)
                        .foregroundColor(.red)
                        .padding(.horizontal)
                }

                Spacer()
            }
            .padding(.top, 24)
            .navigationTitle("Share Souvenir")
            .navigationBarTitleDisplayMode(.inline)
            .toolbarBackground(.thinMaterial, for: .navigationBar)
            .toolbarBackground(.visible, for: .navigationBar)
            .toolbar {
                ToolbarItem(placement: .cancellationAction) {
                    Button("Cancel") {
                        dismiss()
                    }
                }
            }
            .onAppear {
                createShareIfNeeded()
                loadWarnings()
                loadShareImage()
                Task { await updateNotificationPrimerState() }
            }
            .sheet(isPresented: $showingNotificationsPrimer) {
                PermissionPrimerView(
                    systemImageName: "bell.badge.fill",
                    title: "Stay Updated",
                    message: "Notifications let you know when a shared souvenir gets new photos or activity.",
                    primaryButtonTitle: "Enable Notifications",
                    secondaryButtonTitle: "Not Now",
                    onContinue: {
                        didRequestPushPermission = true
                        PushManager.shared.requestAuthorizationAndRegister()
                    },
                    onCancel: {}
                )
            }
            .sheet(isPresented: $showingMessageCompose) {
                if MFMessageComposeViewController.canSendText(),
                   let share = shareEntity {
                    MessageComposeView(
                        souvenir: souvenir,
                        share: share,
                        imageData: shareImageData
                    )
                }
            }
            .sheet(isPresented: $showingActivitySheet) {
                if let share = shareEntity {
                    ActivitySheet(
                        souvenir: souvenir,
                        share: share,
                        imageData: shareImageData
                    )
                }
            }
        }
    }

    // MARK: - Preview Section

    private var previewSection: some View {
        VStack(spacing: 12) {
            // Photo preview
            if let image = shareImage {
                Image(uiImage: image)
                    .resizable()
                    .aspectRatio(contentMode: .fill)
                    .frame(width: 120, height: 120)
                    .clipShape(RoundedRectangle(cornerRadius: 12))
                    .shadow(radius: 4)
            } else if isLoadingImage {
                RoundedRectangle(cornerRadius: 12)
                    .fill(.ultraThinMaterial)
                    .frame(width: 120, height: 120)
                    .overlay(ProgressView())
            }
            else {
                RoundedRectangle(cornerRadius: 12)
                    .fill(.ultraThinMaterial)
                    .frame(width: 120, height: 120)
                    .overlay(
                        Image(systemName: "photo")
                            .font(.largeTitle)
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    )
            }

            // Souvenir title
            Text(souvenir.displayTitle)
                .font(.headline)

            // Caption preview
            if let caption = souvenir.caption, !caption.isEmpty {
                Text(caption)
                    .font(.subheadline)
                    .foregroundStyle(Color.dynamicSecondarySvnr)
                    .lineLimit(2)
                    .multilineTextAlignment(.center)
                    .padding(.horizontal)
            }
        }
    }

    // MARK: - Share Options

    private var shareOptionsSection: some View {
        VStack(spacing: 16) {
            // SMS Share
            Button {
                if MFMessageComposeViewController.canSendText() {
                    showingMessageCompose = true
                } else {
                    errorMessage = "Messages not available on this device"
                }
            } label: {
                HStack {
                    Image(systemName: "message.fill")
                        .font(.title2)
                        .frame(width: 44)

                    VStack(alignment: .leading, spacing: 2) {
                        Text("Send via Messages")
                            .font(.headline)
                        Text("Photo + caption + invite link")
                            .font(.caption)
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    }

                    Spacer()

                    Image(systemName: "chevron.right")
                        .foregroundStyle(Color.dynamicSecondarySvnr)
                }
                .padding()
                .background(.thinMaterial)
                .cornerRadius(12)
            }
            .buttonStyle(.plain)

            // Share Sheet (UIActivityViewController)
            Button {
                showingActivitySheet = true
            } label: {
                HStack {
                    Image(systemName: "square.and.arrow.up")
                        .font(.title2)
                        .frame(width: 44)

                    VStack(alignment: .leading, spacing: 2) {
                        Text("More Options")
                            .font(.headline)
                        Text("AirDrop, Copy Link, and more")
                            .font(.caption)
                            .foregroundStyle(Color.dynamicSecondarySvnr)
                    }

                    Spacer()

                    Image(systemName: "chevron.right")
                        .foregroundStyle(Color.dynamicSecondarySvnr)
                }
                .padding()
                .background(.thinMaterial)
                .cornerRadius(12)
            }
            .buttonStyle(.plain)

            // Link info with tap-to-copy
            if let url = shareURL {
                VStack(spacing: 4) {
                    Text("Link expires in 48 hours")
                        .font(.caption)
                        .foregroundStyle(Color.dynamicSecondarySvnr)

                    Button {
                        UIPasteboard.general.string = url.absoluteString
                        // Brief haptic feedback
                        let generator = UIImpactFeedbackGenerator(style: .light)
                        generator.impactOccurred()
                    } label: {
                        HStack(spacing: 4) {
                            Image(systemName: "doc.on.doc")
                                .font(.caption2)
                            Text(url.absoluteString)
                                .font(.caption2)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                        .foregroundColor(.accent)
                    }
                }
                .padding(.top, 8)
            }
        }
        .padding(.horizontal)
    }

    // MARK: - Helpers

    private func createShareIfNeeded() {
        // Check for existing active share
        let activeShares = shareService.activeShares(for: souvenir, in: context)

        if let existingShare = activeShares.first {
            shareEntity = existingShare
            shareURL = shareService.shareURL(for: existingShare)
        } else {
            // Create new share
            let newShare = shareService.createShare(for: souvenir, in: context)
            shareEntity = newShare
            shareURL = shareService.shareURL(for: newShare)

            // Save context
            do {
                try context.save()
            } catch {
                errorMessage = "Failed to create share link"
            }
        }
    }

    private func loadWarnings() {
        var items = ValidationService.shareWarnings(for: souvenir)
        if let share = shareEntity, let warning = shareService.expirationWarning(for: share) {
            items.append(warning)
        }
        warnings = items
    }

    private func updateNotificationPrimerState() async {
        let settings = await UNUserNotificationCenter.current().notificationSettings()
        if settings.authorizationStatus == .notDetermined {
            if !didRequestPushPermission {
                showingNotificationsPrimer = true
            }
        } else {
            didRequestPushPermission = true
        }
    }

    private func loadShareImage() {
        guard let favoritePhoto = souvenir.favoritePhoto,
              let assetId = favoritePhoto.assetLocalId else {
            return
        }

        isLoadingImage = true

        Task {
            let image = await photoLoader.loadPhoto(
                assetLocalId: assetId,
                targetSize: CGSize(width: 600, height: 600),
                contentMode: .aspectFill
            )

            // Generate JPEG data in the background
            let imageData = image?.jpegData(compressionQuality: 0.8)

            await MainActor.run {
                shareImage = image
                shareImageData = imageData
                isLoadingImage = false
            }
        }
    }
}

private struct WarningBanner: View {
    let messages: [String]

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            ForEach(messages, id: \.self) { message in
                HStack(spacing: 8) {
                    Image(systemName: "exclamationmark.triangle.fill")
                        .foregroundStyle(.warningSvnr)
                    Text(message)
                        .font(.caption)
                        .foregroundStyle(Color.dynamicSecondarySvnr)
                }
            }
        }
        .padding(12)
        .background(.ultraThinMaterial, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 12, style: .continuous)
                .strokeBorder(Color.warningSvnr.opacity(0.4), lineWidth: 1)
        )
        .padding(.horizontal)
    }
}

// MARK: - Message Compose View

struct MessageComposeView: UIViewControllerRepresentable {
    let souvenir: SouvenirEntity
    let share: ShareEntity
    let imageData: Data?

    @Environment(\.dismiss) private var dismiss

    private let shareService = ShareService.shared

    func makeUIViewController(context: Context) -> MFMessageComposeViewController {
        let controller = MFMessageComposeViewController()
        controller.messageComposeDelegate = context.coordinator

        // Pre-populate recipient with contact's phone number
        if let phone = souvenir.primaryContact?.phoneE164, !phone.isEmpty {
            controller.recipients = [phone]
        }

        // Set message body
        controller.body = shareService.smsShareText(for: souvenir, share: share)

        // Attach image if available
        if let imageData = imageData {
            controller.addAttachmentData(imageData, typeIdentifier: "public.jpeg", filename: "souvenir.jpg")
        }

        return controller
    }

    func updateUIViewController(_ uiViewController: MFMessageComposeViewController, context: Context) {}

    func makeCoordinator() -> Coordinator {
        Coordinator(dismiss: dismiss)
    }

    class Coordinator: NSObject, MFMessageComposeViewControllerDelegate {
        let dismiss: DismissAction

        init(dismiss: DismissAction) {
            self.dismiss = dismiss
        }

        func messageComposeViewController(_ controller: MFMessageComposeViewController, didFinishWith result: MessageComposeResult) {
            controller.dismiss(animated: true) {
                self.dismiss()
            }
        }
    }
}

// MARK: - Activity Sheet (UIActivityViewController)

struct ActivitySheet: UIViewControllerRepresentable {
    let souvenir: SouvenirEntity
    let share: ShareEntity
    let imageData: Data?

    private let shareService = ShareService.shared

    func makeUIViewController(context: Context) -> UIActivityViewController {
        var items: [Any] = []

        // Phase 15: Simplified approach for better AirDrop compatibility
        // AirDrop works best with simple items - add image first, then text
        if let imageData = imageData,
           let image = UIImage(data: imageData) {
            // Add image directly for best AirDrop compatibility
            items.append(image)
        }

        // Add share URL for link sharing
        let url = shareService.shareURL(for: share, includeMetadata: true)
        items.append(url)

        let controller = UIActivityViewController(activityItems: items, applicationActivities: nil)

        // Minimal excluded activity types
        controller.excludedActivityTypes = [
            .assignToContact,
            .addToReadingList
        ]

        // Set completion handler for debugging
        controller.completionWithItemsHandler = { activityType, completed, _, error in
            if let error = error {
                print("❌ Share activity failed: \(error.localizedDescription)")
            } else if completed {
                print("✅ Share completed: \(activityType?.rawValue ?? "unknown")")
            }
        }

        return controller
    }

    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
}

// MARK: - Preview

#Preview("Share sheet") {
    // Use comprehensive preview data for Phase 12.1
    let context = PersistenceController.preview.container.viewContext
    let fetchRequest: NSFetchRequest<SouvenirEntity> = {
        let req = SouvenirEntity.fetchRequest()
        req.fetchLimit = 1
        return req
    }()

    if let souvenir = try? context.fetch(fetchRequest).first {
        ShareSheet(souvenir: souvenir)
            .environment(\.managedObjectContext, context)
    } else {
        Text("No preview data available")
    }
}

