@@ -7,10 +7,57 @@

 import SwiftUI
 import CoreData
+import CloudKit
 import UserNotifications

+// MARK: - Notification Names
+
+extension Notification.Name {
+    /// Posted when a share link is opened and a matching souvenir is found locally.
+    /// Object: the souvenir's UUID.
+    static let souvenirShareLinkOpened = Notification.Name("souvenirShareLinkOpened")
+}
+
+// MARK: - App Delegate
+
+/// UIApplicationDelegate bridged for features unavailable in the SwiftUI lifecycle,
+/// specifically CloudKit share acceptance.
+class AppDelegate: NSObject, UIApplicationDelegate {
+
+    /// Called by the system when the user opens a CloudKit share link.
+    /// Accepts the share into the persistent store and records a ShareEntity row.
+    func application(
+        _ application: UIApplication,
+        userDidAcceptCloudKitShareWith cloudKitShareMetadata: CKShare.Metadata
+    ) {
+        let container = PersistenceController.shared.container
+        guard let store = container.persistentStoreCoordinator.persistentStores.first else {
+            print("❌ [Share] No persistent store available for share acceptance.")
+            return
+        }
+        Task {
+            do {
+                let context = container.newBackgroundContext()
+                try await ShareService.shared.acceptShareInvitation(
+                    metadata: cloudKitShareMetadata,
+                    into: store,
+                    container: container,
