//
//  ServicesShareService.swift
//  souvenir
//
//  Phase 3: Sharing
//  Manages share token creation, validation, and Universal Link generation
//

import Foundation
import CoreData
import CryptoKit
import CloudKit

// MARK: - Share State

/// Derived share state for a souvenir based on its ShareEntity rows.
enum ShareState: Equatable {
    /// No shares exist — this souvenir is local only.
    case localOnly
    /// A share was created but the participant has not yet accepted.
    case pendingInvite
    /// At least one participant has accepted and the share is active.
    case sharedActive
    /// All shares have been revoked or declined.
    case sharedRevoked
}

// MARK: - String Constants

/// Raw string values stored in `ShareEntity.status`.
enum ShareStatus {
    static let pending = "pending"
    static let accepted = "accepted"
    static let declined = "declined"
    static let revoked = "revoked"
}

/// Raw string values stored in `ShareEntity.role`.
enum ShareRole {
    static let owner = "owner"
    static let participant = "participant"
}

// MARK: - Errors

enum ShareError: LocalizedError {
    case shareCreationFailed
    case shareURLUnavailable
    case containerUnavailable

    var errorDescription: String? {
        switch self {
        case .shareCreationFailed: return "Failed to create CloudKit share."
        case .shareURLUnavailable: return "Share URL is not yet available."
        case .containerUnavailable: return "CloudKit container is unavailable."
        }
    }
}

/// Service for creating and validating share tokens
final class ShareService {

    // MARK: - Configuration

    /// Universal Link base URL
    static let baseURL = "https://souvenir.kerry.ink"

    /// App Store link for invite
    static let appStoreURL = "https://apps.apple.com/app/id0000000000" // Replace with actual App Store ID

    /// Default token expiration: 48 hours
    static let defaultExpirationInterval: TimeInterval = 48 * 60 * 60

    /// Warning-only helper for upcoming expiration validation (Phase 15.1 scaffolding)
    func expirationWarning(for share: ShareEntity) -> String? {
        let remaining = share.expiresAt.timeIntervalSinceNow
        if remaining <= 0 {
            return "This share link has expired."
        }
        if remaining < 24 * 60 * 60 {
            let hours = max(1, Int(remaining / 3600))
            return "This share link expires in about \(hours) hours."
        }
        return nil
    }

    /// Token length in bytes (URL-safe base64 encoded)
    private static let tokenByteLength = 32

    // MARK: - Singleton

    static let shared = ShareService()
    private init() {}

    // MARK: - Token Generation

    /// Generate a cryptographically secure token
    private func generateToken() -> String {
        var bytes = [UInt8](repeating: 0, count: Self.tokenByteLength)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes).base64EncodedString()
            .replacingOccurrences(of: "+", with: "-")
            .replacingOccurrences(of: "/", with: "_")
            .replacingOccurrences(of: "=", with: "")
    }

    // MARK: - Share Creation

    /// Create a new share for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir to share
    ///   - context: Managed object context
    ///   - expirationInterval: How long until the share expires (default 48 hours)
    /// - Returns: The created ShareEntity
    func createShare(
        for souvenir: SouvenirEntity,
        in context: NSManagedObjectContext,
        expirationInterval: TimeInterval = defaultExpirationInterval
    ) -> ShareEntity {
        let share = ShareEntity(context: context)
        share.id = UUID()
        share.token = generateToken()
        share.createdAt = Date()
        share.expiresAt = Date().addingTimeInterval(expirationInterval)
        share.isRevoked = false
        share.souvenir = souvenir

        return share
    }

    // MARK: - URL Generation

    /// Generate a Universal Link URL for a share
    /// - Parameter share: The share entity
    /// - Returns: The shareable URL
    func shareURL(for share: ShareEntity) -> URL {
        var components = URLComponents(string: Self.baseURL)!
        components.path = "/s/\(share.token)"
        return components.url!
    }

    /// Generate a Universal Link URL with souvenir metadata for deep linking
    /// - Parameters:
    ///   - share: The share entity
    ///   - includeMetadata: Whether to include timestamp/location query params
    /// - Returns: The shareable URL with optional metadata
    ///
    /// Metadata is encoded as a single `m` parameter: base64(timestamp_plusCode)
    /// This obscures the raw values while remaining decodable.
    func shareURL(for share: ShareEntity, includeMetadata: Bool) -> URL {
        var components = URLComponents(string: Self.baseURL)!
        components.path = "/s/\(share.token)"

        if includeMetadata, let souvenir = share.souvenir {
            // Build metadata string: timestamp_plusCode
            var metadataParts: [String] = []

            if let timestamp = souvenir.latestPhotoTimestamp {
                metadataParts.append(String(Int(timestamp.timeIntervalSince1970)))
            }

            // Get plusCode from latest photo
            if let latestPhoto = souvenir.photosArray.first,
               let plusCode = latestPhoto.plusCode, !plusCode.isEmpty {
                metadataParts.append(plusCode)
            }

            if !metadataParts.isEmpty {
                let metadata = metadataParts.joined(separator: "_")
                // Base64 encode to obscure the values
                if let data = metadata.data(using: .utf8) {
                    let encoded = data.base64EncodedString()
                        .replacingOccurrences(of: "+", with: "-")
                        .replacingOccurrences(of: "/", with: "_")
                        .replacingOccurrences(of: "=", with: "")
                    components.queryItems = [URLQueryItem(name: "m", value: encoded)]
                }
            }
        }

        return components.url!
    }

    /// Decode metadata from a share URL
    /// - Parameter url: The incoming URL
    /// - Returns: Tuple of (timestamp, plusCode) if decodable
    func decodeMetadata(from url: URL) -> (timestamp: Date?, plusCode: String?)? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems,
              let mValue = queryItems.first(where: { $0.name == "m" })?.value else {
            return nil
        }

        // Decode base64
        var encoded = mValue
            .replacingOccurrences(of: "-", with: "+")
            .replacingOccurrences(of: "_", with: "/")
        // Add padding if needed
        while encoded.count % 4 != 0 {
            encoded += "="
        }

        guard let data = Data(base64Encoded: encoded),
              let decoded = String(data: data, encoding: .utf8) else {
            return nil
        }

        let parts = decoded.split(separator: "_", maxSplits: 1)
        var timestamp: Date?
        var plusCode: String?

        if let firstPart = parts.first, let epochSeconds = Int(firstPart) {
            timestamp = Date(timeIntervalSince1970: TimeInterval(epochSeconds))
        }

        if parts.count > 1 {
            plusCode = String(parts[1])
        }

        return (timestamp, plusCode)
    }

    // MARK: - Token Validation

    /// Validate a share token and return the associated souvenir
    /// - Parameters:
    ///   - token: The token to validate
    ///   - context: Managed object context
    /// - Returns: The souvenir if valid, nil otherwise
    func validateToken(_ token: String, in context: NSManagedObjectContext) -> SouvenirEntity? {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(
            format: "token == %@ AND isRevoked == NO AND expiresAt > %@",
            token,
            Date() as NSDate
        )
        request.fetchLimit = 1

        guard let share = try? context.fetch(request).first else {
            return nil
        }

        return share.souvenir
    }

    /// Parse a token from a Universal Link or custom scheme URL
    /// - Parameter url: The incoming URL (https://souvenir.kerry.ink/s/TOKEN or souvenir://s/TOKEN)
    /// - Returns: The token if present, nil otherwise
    func parseToken(from url: URL) -> String? {
        // Universal Link: https://souvenir.kerry.ink/s/TOKEN
        // pathComponents = ["/", "s", "TOKEN"]
        let pathComponents = url.pathComponents
        if pathComponents.count >= 2,
           pathComponents[pathComponents.count - 2] == "s" {
            return pathComponents.last
        }

        // Custom URL scheme: souvenir://s/TOKEN
        // host = "s", path = "/TOKEN"
        if url.scheme == "souvenir", url.host == "s" {
            let token = url.path.trimmingCharacters(in: CharacterSet(charactersIn: "/"))
            return token.isEmpty ? nil : token
        }

        return nil
    }

    // MARK: - Share Management

    /// Fetch active shares for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir
    ///   - context: Managed object context
    /// - Returns: Array of active (non-expired, non-revoked) shares
    func activeShares(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) -> [ShareEntity] {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(
            format: "souvenir == %@ AND isRevoked == NO AND expiresAt > %@",
            souvenir,
            Date() as NSDate
        )
        request.sortDescriptors = [NSSortDescriptor(key: "createdAt", ascending: false)]

        return (try? context.fetch(request)) ?? []
    }

    /// Revoke all shares for a souvenir
    /// - Parameters:
    ///   - souvenir: The souvenir
    ///   - context: Managed object context
    func revokeAllShares(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) {
        let shares = activeShares(for: souvenir, in: context)
        shares.forEach { $0.revoke() }
    }

    // MARK: - Share Text Generation

    /// Generate share text for SMS (non-user recipient)
    /// - Parameters:
    ///   - souvenir: The souvenir being shared
    ///   - share: The share entity with token
    /// - Returns: Formatted message text
    func smsShareText(for souvenir: SouvenirEntity, share: ShareEntity) -> String {
        var text = ""

        // Caption or contact name
        if let caption = souvenir.caption, !caption.isEmpty {
            text = caption
        } else if let contactName = souvenir.primaryContact?.displayName {
            text = "Check out my souvenir with \(contactName)!"
        } else {
            text = "Check out my souvenir!"
        }

        // Add view link
        let url = shareURL(for: share)
        text += "\n\n\(url.absoluteString)"

        // Add App Store invite
        text += "\n\nGet Souvenir: \(Self.appStoreURL)"

        return text
    }

    /// Generate share text for in-app sharing (user recipient)
    /// - Parameters:
    ///   - souvenir: The souvenir being shared
    ///   - share: The share entity with token
    /// - Returns: Formatted message text with precise metadata
    func inAppShareText(for souvenir: SouvenirEntity, share: ShareEntity) -> String {
        var text = ""

        // Caption or contact name
        if let caption = souvenir.caption, !caption.isEmpty {
            text = caption
        } else if let contactName = souvenir.primaryContact?.displayName {
            text = "Souvenir with \(contactName)"
        } else {
            text = "A Souvenir"
        }

        // Add deep link with metadata
        let url = shareURL(for: share, includeMetadata: true)
        text += "\n\n\(url.absoluteString)"

        return text
    }

    // MARK: - Share State

    /// Derive the current share state for a souvenir from its ShareEntity rows.
    /// - Parameters:
    ///   - souvenir: The souvenir to check.
    ///   - context: Managed object context.
    func shareState(for souvenir: SouvenirEntity, in context: NSManagedObjectContext) -> ShareState {
        let request = ShareEntity.fetchRequest()
        request.predicate = NSPredicate(format: "souvenir == %@", souvenir)
        guard let shares = try? context.fetch(request), !shares.isEmpty else {
            return .localOnly
        }
        if shares.contains(where: { $0.status == ShareStatus.accepted && !$0.isRevoked }) {
            return .sharedActive
        }
        if shares.contains(where: { $0.status == ShareStatus.pending && !$0.isRevoked }) {
            return .pendingInvite
        }
        return .sharedRevoked
    }

    // MARK: - CloudKit Share Lifecycle

    /// Create a CKShare for a souvenir and save the owner's ShareEntity row.
    /// - Parameters:
    ///   - souvenir: The souvenir to share.
    ///   - container: The NSPersistentCloudKitContainer.
    ///   - context: Managed object context for saving ShareEntity.
    ///   - inviterUserId: Current user's CloudKit record name (from CKCurrentUserDefaultName or fetched identity).
    /// - Returns: The CKShare URL to send to the recipient.
    func createAndSaveShare(
        for souvenir: SouvenirEntity,
        container: NSPersistentCloudKitContainer,
        in context: NSManagedObjectContext,
        inviterUserId: String
    ) async throws -> URL {
        // Pre-compute values from non-Sendable souvenir before the @Sendable closure
        let souvenirTitle = souvenir.displayTitle
        let souvenirIDString = souvenir.id.uuidString
        let souvenirObjectID = souvenir.objectID

        let share: CKShare = try await withCheckedThrowingContinuation { continuation in
            container.share([souvenir], to: nil) { _, share, _, error in
                if let error = error {
                    continuation.resume(throwing: error)
                    return
                }
                guard let share else {
                    continuation.resume(throwing: ShareError.shareCreationFailed)
                    return
                }
                share[CKShare.SystemFieldKey.title] = souvenirTitle as CKRecordValue
                continuation.resume(returning: share)
            }
        }

        guard let shareURL = share.url else {
            throw ShareError.shareURLUnavailable
        }

        let shareRecordName = share.recordID.recordName
        try await context.perform {
            let shareEntity = ShareEntity(context: context)
            shareEntity.id = UUID()
            shareEntity.createdAt = Date()
            shareEntity.expiresAt = Date().addingTimeInterval(72 * 60 * 60)
            shareEntity.isRevoked = false
            shareEntity.token = shareRecordName
            shareEntity.status = ShareStatus.pending
            shareEntity.role = ShareRole.owner
            shareEntity.inviterUserId = inviterUserId
            shareEntity.cloudKitShareRecordName = shareRecordName
            shareEntity.cloudKitRootRecordName = souvenirIDString
            shareEntity.souvenir = context.object(with: souvenirObjectID) as? SouvenirEntity
            try context.save()
        }

        return shareURL
    }

    /// Revoke a share — marks the ShareEntity revoked locally.
    /// CloudKit participant removal is left to the system on next sync.
    /// - Parameters:
    ///   - shareEntity: The share to revoke.
    ///   - context: Managed object context.
    func revokeShare(
        _ shareEntity: ShareEntity,
        in context: NSManagedObjectContext
    ) async throws {
        let objectID = shareEntity.objectID
        try await context.perform {
            guard let share = context.object(with: objectID) as? ShareEntity else { return }
            share.isRevoked = true
            share.revokedAt = Date()
            share.status = ShareStatus.revoked
            try context.save()
        }
    }

    /// Accept a CloudKit share invitation and record the participation in Core Data.
    /// Call this from the UIApplicationDelegate share-acceptance callback.
    /// - Parameters:
    ///   - metadata: CKShare.Metadata received from the system.
    ///   - persistentStore: The NSPersistentStore to import the shared zone into.
    ///   - container: The NSPersistentCloudKitContainer.
    ///   - context: Managed object context.
    func acceptShareInvitation(
        metadata: CKShare.Metadata,
        into persistentStore: NSPersistentStore,
        container: NSPersistentCloudKitContainer,
        in context: NSManagedObjectContext
    ) async throws {
        try await withCheckedThrowingContinuation { (continuation: CheckedContinuation<Void, Error>) in
            container.acceptShareInvitations(from: [metadata], into: persistentStore) { _, error in
                if let error = error {
                    continuation.resume(throwing: error)
                } else {
                    continuation.resume()
                }
            }
        }

        let shareRecordName = metadata.share.recordID.recordName
        let rootRecordName = metadata.hierarchicalRootRecordID?.recordName ?? metadata.share.recordID.recordName

        try await context.perform {
            let shareEntity = ShareEntity(context: context)
            shareEntity.id = UUID()
            shareEntity.createdAt = Date()
            shareEntity.expiresAt = Date().addingTimeInterval(72 * 60 * 60)
            shareEntity.isRevoked = false
            shareEntity.token = shareRecordName
            shareEntity.status = ShareStatus.accepted
            shareEntity.acceptedAt = Date()
            shareEntity.role = ShareRole.participant
            shareEntity.cloudKitShareRecordName = shareRecordName
            shareEntity.cloudKitRootRecordName = rootRecordName
            // souvenir will be linked by CloudKit sync after acceptance
            try context.save()
        }
    }
}

