struct MessageComposeView: UIViewControllerRepresentable {
    let souvenir: SouvenirEntity
    let share: ShareEntity
    let imageData: Data?

    @Environment(\.dismiss) private var dismiss

    private let shareService = ShareService.shared

    func makeUIViewController(context: Context) -> MFMessageComposeViewController {
        let controller = MFMessageComposeViewController()
        controller.messageComposeDelegate = context.coordinator

        // Pre-populate recipient with contact's phone number
        if let phone = souvenir.primaryContact?.phoneE164, !phone.isEmpty {
            controller.recipients = [phone]
        }

        // Set message body
        controller.body = shareService.smsShareText(for: souvenir, share: share)

        // Attach image if available
        if let imageData = imageData {
            controller.addAttachmentData(imageData, typeIdentifier: "public.jpeg", filename: "souvenir.jpg")
        }

        return controller
    }

    func updateUIViewController(_ uiViewController: MFMessageComposeViewController, context: Context) {}

    func makeCoordinator() -> Coordinator {
        Coordinator(dismiss: dismiss)
    }

    class Coordinator: NSObject, MFMessageComposeViewControllerDelegate {
        let dismiss: DismissAction

        init(dismiss: DismissAction) {
            self.dismiss = dismiss
        }

        func messageComposeViewController(_ controller: MFMessageComposeViewController, didFinishWith result: MessageComposeResult) {
            controller.dismiss(animated: true) {
                self.dismiss()
            }
        }
    }
}

// MARK: - Activity Sheet (UIActivityViewController)

struct ActivitySheet: UIViewControllerRepresentable {
    let souvenir: SouvenirEntity
    let share: ShareEntity
    let imageData: Data?

    private let shareService = ShareService.shared

    func makeUIViewController(context: Context) -> UIActivityViewController {
        var items: [Any] = []

        // Phase 15: Simplified approach for better AirDrop compatibility
        // AirDrop works best with simple items - add image first, then text
        if let imageData = imageData,
           let image = UIImage(data: imageData) {
            // Add image directly for best AirDrop compatibility
            items.append(image)
        }

        // Add share URL for link sharing
        let url = shareService.shareURL(for: share, includeMetadata: true)
        items.append(url)

        let controller = UIActivityViewController(activityItems: items, applicationActivities: nil)

        // Minimal excluded activity types
        controller.excludedActivityTypes = [
            .assignToContact,
            .addToReadingList
        ]

        // Set completion handler for debugging
        controller.completionWithItemsHandler = { activityType, completed, _, error in
            if let error = error {
                print("❌ Share activity failed: \(error.localizedDescription)")
            } else if completed {
                print("✅ Share completed: \(activityType?.rawValue ?? "unknown")")
            }
        }

        return controller
    }

    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
}

