/// Create or reuse a CloudKit-backed share for this souvenir.
/// Reuses an existing active share (and its persisted URL) if one exists.
/// Falls back to a local token share if the user is not signed into iCloud.
@MainActor
private func createShareIfNeeded() async {
    // Reuse existing active share
    let activeShares = shareService.activeShares(for: souvenir, in: context)
    if let existing = activeShares.first {
        shareEntity = existing
